#include <cstdio>
#include <cstdlib>

#define N 15

int board[N][N];

bool isSafe(int row, int col) {
    for (int i = 0; i < col; i++)
        if (board[row][i])
            return false;

    for (int i = row, j = col; i >= 0 && j >= 0; i--, j--)
        if (board[i][j])
            return false;

    for (int i = row, j = col; j >= 0 && i < N; i++, j--)
        if (board[i][j])
            return false;

    return true;
}

bool solveNQUtil(int col) {
    if (col >= N)
        return true;

    for (int i = 0; i < N; i++) {
        if (isSafe(i, col)) {
            board[i][col] = 1;

            if (solveNQUtil(col + 1))
                return true;

            board[i][col] = 0;
        }
    }
    return false;
}

int main() {
    // Initialize board to 0
    for (int i = 0; i < N; i++)
        for (int j = 0; j < N; j++)
            board[i][j] = 0;

    bool res = false;

    #pragma omp target data map(tofrom: board)
    {
        #pragma omp target map(tofrom: res)
        {
            res = solveNQUtil(0);
        }
    }

    if (res) {
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++)
                printf("%d ", board[i][j]);
            printf("\n");
        }
    } else {
        printf("No solution exists\n");
    }

    return 0;
}
